@implements IDisposable
@inject IAddressValidator AddressValidator

<fieldset disabled="@_isValidating">
    <div class="mb-3">
        <label>Name</label>
        <input class="form-control" @bind="Shipping.Name" />
    </div>
    <div class="mb-3">
        <label>Address</label>
        <input class="form-control" @bind="Shipping.Address" />
    </div>
    <div class="mb-3">
        <label>City</label>
        <input class="form-control" @bind="Shipping.City" />
    </div>
    <div class="mb-3">
        <label>Zip Code</label>
        <input class="form-control" @bind="Shipping.ZipCode" />
    </div>
</fieldset>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<button class="btn btn-primary" @onclick="ValidateAndProceed" disabled="@_isValidating">
    @if (_isValidating)
    {
        <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _errorMessage;

    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = default!;

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        _errorMessage = null;

        // Cancel any in-flight validation (e.g. user went back and changed fields).
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _errorMessage = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was superseded or the component is being disposed — nothing to do.
        }
        finally
        {
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

